async (params, browser) => {
  // Search Airbnb listings
  await browser.open(`https://www.airbnb.com/s/${params.location}/homes`)

  // Wait for search results
  await browser.waitForSelector('[itemprop=\'itemListElement\'], [data-testid=\'card-container\'], [data-testid=\'listing-card-title\']', 15000)

  // Let results render
  await browser.wait(3000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll for more listings
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Extract listing results
  const search_results = await browser.evaluate(`const results = []; const cards = document.querySelectorAll('[itemprop="itemListElement"], [data-testid="card-container"], [aria-labelledby]'); for (let i = 0; i < Math.min(cards.length, 15); i++) { const el = cards[i]; const titleEl = el.querySelector('[data-testid="listing-card-title"], [id^="title_"]'); const subtitleEl = el.querySelector('[data-testid="listing-card-subtitle"]'); const priceEl = el.querySelector('[data-testid="price-availability-row"] span span, ._tyxjp1, span._14y1168'); const ratingEl = el.querySelector('[aria-label*="rating"], .t1a9j9y7 span, svg[aria-label*="Rating"] + span'); const linkEl = el.querySelector('a[href*="/rooms/"]'); const imgEl = el.querySelector('img[src*="images"], img[data-original-uri]'); const bedsEl = el.querySelector('[data-testid="listing-card-subtitle"]:last-of-type'); const url = linkEl ? (linkEl.href.startsWith('http') ? linkEl.href : 'https://www.airbnb.com' + linkEl.getAttribute('href')) : ''; const title = titleEl ? titleEl.textContent.trim() : ''; if (title) { results.push({ title: title, subtitle: subtitleEl ? subtitleEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', property_type: bedsEl ? bedsEl.textContent.trim() : '', image: imgEl ? (imgEl.getAttribute('src') || imgEl.getAttribute('data-original-uri') || '') : '', url: url }); } } return { location: params.location, result_count: results.length, results: results }`)

  return search_results
}
